const path = require('path');
const fs = require('fs');
const crypto = require('crypto');
const buffer = fs.readFileSync(path.join(__dirname, 'app.apk'));
const hash = crypto.createHash('md5');
hash.update(buffer, 'utf8');
const md5 = hash.digest('hex');
console.log(md5);
